21	const basePremiumByType: Record<string, number> = {
22	  amulet: 60,
23	  sword: 100,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	};
28	
29	const PROCESSING_FEE = 5;
30	
31	export function quote(
32	  _customer: Customer,
33	  items: Item[],
34	  _options: QuoteOptions = {},
35	): QuoteResult {
36	  const basePremium =
37	    items.length === 3 && items.every((item) => item.type === "rune")
38	      ? 60
39	      : items.reduce((sum, item) => sum + basePremiumByType[item.type], 0);
40	  const premium = items.length === 0 ? PROCESSING_FEE : 0;
41	  return { basePremium, premium };
42	}
